BEGIN
    SET NOCOUNT ON;
    UPDATE ds
    SET ds.[CompanyName] = ss.[CompanyName],
        ds.[Phone] = ss.[Phone]
    FROM [dbo].[DimShipper] ds
    INNER JOIN [staging].[Shipper] ss ON (ds.[ShipperSK] = ss.[ShipperSK]);

END;

BEGIN SET NOCOUNT ON;
UPDATE fs SET fs.[OrderDateKey] = stg.[OrderDateKey], fs.[RequiredDateKey] = stg.[RequiredDateKey], fs.[ShippedDateKey] = stg.[ShippedDateKey], fs.[CustomerSK] = stg.[CustomerSK], fs.[ProductSK] = stg.[ProductSK], fs.[EmployeeSK] = stg.[EmployeeSK], fs.[ShipperSK] = stg.[ShipperSK], fs.[Quantity] = stg.[Quantity], fs.[UnitPrice] = stg.[UnitPrice], fs.[Discount] = stg.[Discount], fs.[OrderDate] = stg.[OrderDate], fs.[RequiredDate] = stg.[RequiredDate], fs.[ShippedDate] = stg.[ShippedDate]
FROM [dbo].[FactOrders] fs INNER JOIN [staging].[Orders] stg ON fs.[OrderID] = stg.[OrderID] AND fs.[ProductID] = stg.[ProductID]; END;

BEGIN SET NOCOUNT ON;
IF NOT EXISTS (SELECT 1 FROM dbo.DimDate WHERE DateKey = 0) BEGIN INSERT INTO dbo.DimDate (DateKey, FullDate, [Year], [Quarter], [Month], [MonthName], [Day]) VALUES (0, '1900-01-01', 1900, 0, 0, 'Desconocido', 0); END
WHILE @StartDate <= @EndDate BEGIN INSERT INTO dbo.DimDate ( DateKey, FullDate, [Year], [Quarter], [Month], [MonthName], [Day] ) SELECT CONVERT(INT, CONVERT(VARCHAR(8), @StartDate, 112)) AS DateKey, @StartDate AS FullDate, DATEPART(YEAR, @StartDate) AS [Year], DATEPART(QUARTER, @StartDate) AS [Quarter], DATEPART(MONTH, @StartDate) AS [Month], DATENAME(MONTH, @StartDate) AS [MonthName], DATEPART(DAY, @StartDate) AS [Day] WHERE NOT EXISTS ( SELECT 1 FROM dbo.DimDate WHERE DateKey = CONVERT(INT, CONVERT(VARCHAR(8), @StartDate, 112)) );
SET @StartDate = DATEADD(DAY, 1, @StartDate); END
END;

BEGIN
    SELECT LastRowVersion
    FROM [dbo].[PackageConfig]
    WHERE TableName = @tableName;
END;

BEGIN
    UPDATE [dbo].[PackageConfig]
    SET LastRowVersion = @lastRowVersion
    WHERE TableName = @tableName;
END;
